{
    "code": "ct_pds_interface",
    "description": "Table des fichiers json des pds",
    "disabled": false,
    "name": "ct_pds_interface",
    "storeInES": false,
    "storeAsTable": true,
    "field": [
        {
            "code": "nom_fichier",
            "description": "Nom du fichier",
            "fieldType": "STRING"
        },
        {
            "code": "date_last_update",
            "description": "Date de dernière modification du statut",
            "fieldType": "STRING"
        },
        {
            "code": "statut",
            "description": "Statut",
            "fieldType": "LIST",
            "listValues": {
                "DECOUPE": "DECOUPE",
                "A_TRAITER": "A_TRAITER",
                "ERREUR": "ERREUR"
            }
        },
        {
            "code": "message_erreur",
            "description": "Message d'erreur",
            "fieldType": "STRING",
            "maxValue": 4000
        },
        {
            "code": "date_traitement",
            "description": "Date de traitement",
            "fieldType": "STRING"
        }
    ],
    "action": []
}
